import React, { useState } from 'react';

const campos = [
  { name: 'CNPJ', label: 'CNPJ' },
  { name: 'ANO', label: 'Ano' },
  { name: 'ID_ESTACAO', label: 'ID Estação' },
  { name: 'NU_ESTACAO_BDTA_ANATEL', label: 'Nº Estação BDTA Anatel' },
  { name: 'LAT', label: 'Latitude' },
  { name: 'LONG', label: 'Longitude' },
  { name: 'CO_MUNICIPIO_IBGE', label: 'Cód. Município IBGE' },
  { name: 'ENDERECO', label: 'Endereço' },
  { name: 'SN_ABERTURA', label: 'Sinal Abertura' },
  { name: 'TP_ESTACAO', label: 'Tipo Estação' },
  { name: 'SN_ENLACE_PROPRIO', label: 'Enlace Próprio' },
  { name: 'SN_ENLACE_CONTRATADO', label: 'Enlace Contratado' },
  { name: 'SN_ENLACE_SATELITE', label: 'Enlace Satélite' }
];

export default function EstacoesInfra() {
  const [form, setForm] = useState({});
  const [linhas, setLinhas] = useState([]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleAddLinha = (e) => {
    e.preventDefault();
    setLinhas([...linhas, form]);
    setForm({});
  };

  const handleExportCSV = () => {
    const header = campos.map(c => c.name).join(';');
    const csv = [header, ...linhas.map(linha => campos.map(c => linha[c.name] || '').join(';'))].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'EX_ESTACOES.csv';
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div style={{ padding: 24 }}>
      <h2 style={{ textAlign: 'center', marginBottom: 24 }}>Cadastro de Estações</h2>
      <form onSubmit={handleAddLinha} style={{ display: 'flex', flexWrap: 'wrap', gap: 16, marginBottom: 24 }}>
        {campos.map(campo => (
          <div key={campo.name} style={{ display: 'flex', flexDirection: 'column', minWidth: 180 }}>
            <label style={{ fontWeight: 600 }}>{campo.label}</label>
            <input
              name={campo.name}
              value={form[campo.name] || ''}
              onChange={handleChange}
              style={{ padding: 6, borderRadius: 4, border: '1px solid #ccc' }}
              required={campo.name !== 'SN_ENLACE_PROPRIO' && campo.name !== 'SN_ENLACE_CONTRATADO' && campo.name !== 'SN_ENLACE_SATELITE'}
            />
          </div>
        ))}
        <button type="submit" style={{ height: 40, alignSelf: 'end', background: '#1976d2', color: '#fff', border: 'none', borderRadius: 6, padding: '0 18px', fontWeight: 600, cursor: 'pointer' }}>Adicionar</button>
      </form>
      <button onClick={handleExportCSV} style={{ background: '#388e3c', color: '#fff', border: 'none', borderRadius: 6, padding: '8px 24px', fontWeight: 600, fontSize: 16, marginBottom: 24, cursor: 'pointer' }}>
        Exportar CSV
      </button>
      <table style={{ width: '100%', borderCollapse: 'collapse', marginTop: 16 }}>
        <thead>
          <tr>
            {campos.map(campo => (
              <th key={campo.name} style={{ border: '1px solid #ccc', padding: 8, background: '#f4f4f4' }}>{campo.label}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {linhas.map((linha, idx) => (
            <tr key={idx}>
              {campos.map(campo => (
                <td key={campo.name} style={{ border: '1px solid #ccc', padding: 8 }}>{linha[campo.name]}</td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
